;(()=>{
  const N=TECH.length,g=Math.PI*(3-Math.sqrt(5))
  TECH.forEach((t,i)=>{
    const y=1-(i/(N-1))*2,r=Math.sqrt(Math.max(0,1-y*y)),th=g*i
    t.px=Math.cos(th)*r;t.py=y;t.pz=Math.sin(th)*r
  })
})()

