/* ─── DOTTED WAVE ───────────────────────────────────────────── */
function DottedWave(){
  const ref=useRef(null),raf=useRef(null)
  useEffect(()=>{
    const cv=ref.current; if(!cv) return
    const ctx=cv.getContext('2d')
    let t=0
    const resize=()=>{cv.width=cv.offsetWidth||900;cv.height=cv.offsetHeight||380}
    resize();window.addEventListener('resize',resize)
    const draw=()=>{
      const W=cv.width,H=cv.height
      ctx.clearRect(0,0,W,H)
      const COLS=44,ROWS=14,dx=W/COLS,dy=H/ROWS
      for(let r=0;r<ROWS;r++){
        for(let c=0;c<COLS;c++){
          const wave=Math.sin((c/COLS*9+t)*1.1)*10+Math.sin((r/ROWS*7+t*.75)*1.3)*7
          const x=c*dx+dx/2,y=r*dy+dy/2+wave
          const ef=Math.abs(c-COLS/2)/(COLS/2),rf=r/ROWS
          const op=(1-ef*.75)*(0.07+rf*.42)*.48
          ctx.beginPath();ctx.arc(x,y,1.1+rf*.65,0,Math.PI*2)
          ctx.fillStyle=`rgba(124,58,237,${op})`;ctx.fill()
        }
      }
      t+=0.036;raf.current=requestAnimationFrame(draw)
    }
    draw()
    return()=>{cancelAnimationFrame(raf.current);window.removeEventListener('resize',resize)}
  },[])
  return(
    <canvas ref={ref} style={{position:'absolute',bottom:'-60px',left:0,width:'100%',height:'55%',
      pointerEvents:'none',zIndex:1,
      maskImage:'linear-gradient(to bottom,transparent 0%,rgba(0,0,0,.3) 20%,rgba(0,0,0,.6) 48%,rgba(0,0,0,.3) 78%,transparent 100%)',
      WebkitMaskImage:'linear-gradient(to bottom,transparent 0%,rgba(0,0,0,.3) 20%,rgba(0,0,0,.6) 48%,rgba(0,0,0,.3) 78%,transparent 100%)'}}/>
  )
}

/* ─── FIX ICON URL (force white for icongr.am, passthrough others) */
const fixIcon = url => {
  if(!url) return 'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/devicon/devicon-original.svg'
  if(url.includes('icongr.am')) return url.replace('color=currentColor','color=ffffff')
  return url
}
