function CertLightbox({cert,onClose}){
  if(!cert) return null
  return(
    <div onClick={onClose} style={{position:'fixed',inset:0,zIndex:900,
      background:'rgba(0,0,0,.88)',backdropFilter:'blur(8px)',
      display:'flex',alignItems:'center',justifyContent:'center',padding:'20px'}}>
      <div onClick={e=>e.stopPropagation()} style={{maxWidth:'min(92vw,900px)',width:'100%',
        background:'#0f0e1a',borderRadius:20,overflow:'hidden',
        border:'1px solid rgba(255,255,255,.1)',boxShadow:'0 30px 80px rgba(0,0,0,.7)'}}>
        {/* Header */}
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',
          padding:'16px 20px',borderBottom:'1px solid rgba(255,255,255,.07)',
          background:'rgba(124,58,237,.08)'}}>
          <div>
            <p style={{fontSize:16,fontWeight:700,color:'#fff',fontFamily:"'Syne',sans-serif"}}>{cert.name}</p>
            <p style={{fontSize:12,color:'rgba(255,255,255,.5)',marginTop:2}}>{cert.provider} · {cert.year}</p>
          </div>
          <div style={{display:'flex',alignItems:'center',gap:12}}>
            {cert.verify&&(
              <a href={cert.verify} target="_blank" rel="noreferrer"
                style={{fontSize:12,color:'#7c3aed',textDecoration:'none',border:'1px solid rgba(124,58,237,.4)',
                  borderRadius:100,padding:'5px 14px',transition:'all .2s'}}
                onMouseEnter={e=>e.currentTarget.style.background='rgba(124,58,237,.15)'}
                onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
                Verify ↗
              </a>
            )}
            <button onClick={onClose} style={{background:'rgba(255,255,255,.08)',border:'1px solid rgba(255,255,255,.1)',
              borderRadius:8,width:34,height:34,cursor:'pointer',color:'#fff',
              display:'flex',alignItems:'center',justifyContent:'center'}}>
              <X size={16}/>
            </button>
          </div>
        </div>
        {/* Certificate image */}
        <div style={{padding:'0',background:'#1a1826',maxHeight:'75vh',overflow:'auto'}}>
          <img src={cert.img} alt={cert.name}
            style={{width:'100%',display:'block',objectFit:'contain'}}/>
        </div>
      </div>
    </div>
  )
}

